def search(request: Request):
    table = request.args.get("table", DEFAULT_TABLE)
    if table not in ALLOWED_TABLES:
        return json_response({"error": "invalid table"}, 400)

    allowed_columns = ALLOWED_COLUMNS[table]

    select_fields = request.args.get("fields")
    if select_fields:
        requested = [f.strip() for f in select_fields.split(",") if f.strip()]
        columns = [allowed_columns[f] for f in requested if f in allowed_columns]
        if not columns:
            columns = list(allowed_columns.values())
    else:
        columns = list(allowed_columns.values())

    where_clauses = []
    params = []

    for public_name, db_column in allowed_columns.items():
        value = request.args.get(public_name)
        if value is not None and value != "":
            where_clauses.append(f"`{db_column}` = %s")
